package migration

import (
	"bytes"
	"compress/gzip"
	"context"
	"crypto/sha256"
	"database/sql"
	"encoding/base64"
	"encoding/hex"
	"fmt"
	"io"
)

const (
	version3ContractDigest     = "a523d6c4aeebb386780f7283b63aacb175cf0420027114edac51a032425615a2"
	version3ContractGZIPBase64 = ""
)

var frozenVersion3Contract = mustDecodeVersion3Contract()

func Version3SchemaContract() []byte { return append([]byte(nil), frozenVersion3Contract...) }

func ValidateVersion3SchemaContract(ctx context.Context, connection *sql.Conn) error {
	actual, err := BuildSchemaContract(ctx, connection, 3)
	if err != nil {
		return err
	}
	if !bytes.Equal(actual, frozenVersion3Contract) {
		return fmt.Errorf("validate version 3 schema contract: digest %x, want %s", sha256.Sum256(actual), version3ContractDigest)
	}
	return nil
}

func mustDecodeVersion3Contract() []byte {
	compressed, err := base64.StdEncoding.DecodeString(version3ContractGZIPBase64)
	if err != nil {
		panic(fmt.Sprintf("decode frozen version 3 contract: %v", err))
	}
	reader, err := gzip.NewReader(bytes.NewReader(compressed))
	if err != nil {
		panic(fmt.Sprintf("open frozen version 3 contract: %v", err))
	}
	contract, err := io.ReadAll(io.LimitReader(reader, 1024*1024))
	if err != nil {
		panic(fmt.Sprintf("read frozen version 3 contract: %v", err))
	}
	if err := reader.Close(); err != nil {
		panic(fmt.Sprintf("close frozen version 3 contract: %v", err))
	}
	digest := sha256.Sum256(contract)
	if hex.EncodeToString(digest[:]) != version3ContractDigest {
		panic(fmt.Sprintf("frozen version 3 contract digest = %x, want %s", digest, version3ContractDigest))
	}
	return contract
}
